# Category: insecure_upload

from flask import Flask, request, jsonify, send_from_directory, url_for, abort
from werkzeug.utils import secure_filename
from PIL import Image
import os
import uuid

app = Flask(__name__)

BASE_DIR = os.path.dirname(os.path.abspath(__file__))
UPLOAD_DIR = os.path.join(BASE_DIR, "uploads", "profile_pics")
os.makedirs(UPLOAD_DIR, exist_ok=True)

MAX_CONTENT_LENGTH = 5 * 1024 * 1024  # 5MB
app.config["MAX_CONTENT_LENGTH"] = MAX_CONTENT_LENGTH

ALLOWED_EXTENSIONS = {"jpg", "jpeg", "png", "gif", "webp"}


def allowed_file(filename: str) -> bool:
    if not filename or "." not in filename:
        return False
    ext = filename.rsplit(".", 1)[1].lower()
    return ext in ALLOWED_EXTENSIONS


def save_image(file_storage, user_id: str) -> dict:
    filename = secure_filename(file_storage.filename or "")
    if not allowed_file(filename):
        abort(400, description="Unsupported file type")

    try:
        file_storage.stream.seek(0)
        img = Image.open(file_storage.stream)
        img.verify()
    except Exception:
        abort(400, description="Invalid image file")

    file_storage.stream.seek(0)
    img = Image.open(file_storage.stream)

    if img.mode not in ("RGB", "RGBA"):
        img = img.convert("RGBA")

    max_size = (1024, 1024)
    img.thumbnail(max_size)

    ext = filename.rsplit(".", 1)[1].lower()
    if ext in ("jpg", "jpeg"):
        out_ext = "jpg"
        img = img.convert("RGB")
        pil_format = "JPEG"
    elif ext == "png":
        out_ext = "png"
        pil_format = "PNG"
    elif ext == "gif":
        out_ext = "gif"
        pil_format = "GIF"
    elif ext == "webp":
        out_ext = "webp"
        pil_format = "WEBP"
    else:
        abort(400, description="Unsupported file type")

    unique = uuid.uuid4().hex
    out_name = f"user_{secure_filename(user_id)}_{unique}.{out_ext}"
    out_path = os.path.join(UPLOAD_DIR, out_name)

    save_kwargs = {}
    if pil_format == "JPEG":
        save_kwargs.update({"quality": 90, "optimize": True})
    elif pil_format == "PNG":
        save_kwargs.update({"optimize": True})
    elif pil_format == "WEBP":
        save_kwargs.update({"quality": 85, "method": 6})

    try:
        img.save(out_path, pil_format, **save_kwargs)
    except Exception:
        abort(500, description="Failed to save image")

    return {
        "filename": out_name,
        "url": url_for("get_profile_picture", filename=out_name, _external=True),
    }


@app.post("/api/profile-picture")
def upload_profile_picture():
    user_id = request.form.get("user_id") or request.headers.get("X-User-Id")
    if not user_id:
        abort(400, description="Missing user_id")

    if "picture" not in request.files:
        abort(400, description="Missing file field 'picture'")

    f = request.files["picture"]
    if not f or not f.filename:
        abort(400, description="No selected file")

    result = save_image(f, user_id)
    return jsonify({"ok": True, **result}), 201


@app.get("/uploads/profile-pics/<path:filename>")
def get_profile_picture(filename):
    filename = secure_filename(filename)
    if not filename:
        abort(404)
    return send_from_directory(UPLOAD_DIR, filename)


@app.errorhandler(413)
def too_large(_e):
    return jsonify({"ok": False, "error": "File too large"}), 413


@app.errorhandler(400)
def bad_request(e):
    return jsonify({"ok": False, "error": getattr(e, "description", "Bad request")}), 400


@app.errorhandler(404)
def not_found(_e):
    return jsonify({"ok": False, "error": "Not found"}), 404


@app.errorhandler(500)
def server_error(e):
    return jsonify({"ok": False, "error": getattr(e, "description", "Server error")}), 500


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", "5000")), debug=True)